var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"호수의 파편이다! 우리는 호수의 품에 한 발짝 다가선 것이다!","JPN":"湖の破片だ！　私たちは湖に一歩近づいたのだ！","ENG":"It's a Fragment of the Lake! We are a step closer into the arms of the Lake!","TWN":"是湖水碎片！我們距離湖水的懷抱又近了一步！"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"마침내……! 마침내 우리의 오랜 숙원에 새로운 길이 열렸구나……!","JPN":"ついに……！　ついに私たちの長年の念願に新しい道が開かれた……！","ENG":"Alas...! A new path for our long-awaited wishes has finally opened...!","TWN":"終於……！終於我們的願望有了新的出路……！"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"학회원들이 동요하고 있군. 쉽게 가라앉지는 않겠어.","JPN":"学会員たちが動揺しているな。簡単には落ち着かないだろう。","ENG":"They are getting excited. This won't be easy to calm them down.","TWN":"學會成員都很激動。應該沒那麼容易平靜下來。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"저것이 오래 전 기관에게 빼앗긴 파편이오?","JPN":"あれが昔、機関に奪われた破片なのか？","ENG":"Is that the Fragment that the Institution stole from us so long ago?","TWN":"那個就是很久以前被機關搶走的碎片嗎？"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"네. 그렇답니다. 아직 이 세계에 남아 있는 저희 중에는 매우 거대한 축에 속하죠.","JPN":"はい。そうです。まだこの世界に残っている我々の中では巨大な部類に入ります。","ENG":"Yes, that is correct. It is one of the largest Fragments of us that remain in this world.","TWN":"嗯，是的。在還留在這個世界的我們當中，也屬於非常龐大的一類。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"그런가. 실로 감격스러운 순간이로군.","JPN":"そうか。実に感激的な瞬間であるな。","ENG":"Is that so? A truly thrilling moment, this is...","TWN":"是嗎，真是激動人心的時刻。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"저 파편으로 얼마나 많은 위업을 이룰 수 있을지…… 상상할 수 없을 지경이오.","JPN":"あの破片でどれほど多くの偉業が達成されていくのか……想像もできないくらいだ。","ENG":"I cannot imagine... what astonishing feats we can accomplish with it.","TWN":"用那個碎片可以成就多少豐功偉業……簡直無法想像。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"아. 의식을 치를 계획이에요.","JPN":"そうでした、儀式を行おうと思っていたんです。","ENG":"Oh. We are planning to perform a ritual.","TWN":"啊，我們打算舉行儀式。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"의식이라……. 어떤 의식이오?","JPN":"儀式……どのような儀式だ？","ENG":"A ritual...? Of what kind?","TWN":"儀式……什麼儀式？"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"이 세계의 법칙에 종속되지 않은, 다른 세계의 존재를 불러들이는 의식이랍니다.","JPN":"この世界の法則に属さない、違う世界の存在を呼び寄せる儀式です。","ENG":"A ritual that can summon beings from other realms who defies the laws of this world.","TWN":"召喚不附屬於這個世界法則的，其他世界存在的儀式。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"호오…… 그거 흥미롭구려. 고고학부장이 꽤나 아쉬워하겠소.","JPN":"ほう……それは興味深い。考古学部長が大いに残念がるだろうな。","ENG":"Ho-oh... Interesting. The Dean of Archeology must be very disappointed.","TWN":"噢噢……這個很有意思啊。考古學院院長看不到應該會很遺憾吧。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"괜찮아요. 교수님은 스스로 본인의 길을 개척할 역량이 있으시니까요.","JPN":"大丈夫です。教授はご自身で自らの道を開拓する力量をお持ちですから。","ENG":"It's okay. The Professor is fully capable of paving his own way.","TWN":"沒關係，因為教授有能力自行開闢自己的道路。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"그보다…… 준비는 어떻게 되어 가나요, 네퀴티아?","JPN":"それより……準備はどうですか？　ネキティア。","ENG":"Aside from that... Nequitia, how are things going with the preparations?","TWN":"話說回來……準備得怎麼樣了，莉奎蒂亞？"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"필요한 인원이 아직 도착하지 않았더군요, 왕이시여.","JPN":"必要な人員がまだ到着しておりません、王様。","ENG":"My lord, the required personnel has not arrived yet.","TWN":"需要的人員還沒有到齊，我的王。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"현재로서는 무대가 마련되어도 연주를 시작할 수 없습니다.","JPN":"現時点では舞台が用意されても演奏を始めることはできません。","ENG":"Even though the stage is set, we cannot begin the performance right now.","TWN":"即使現在舞台已經準備好了，暫時也不能開始演奏。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"필요한 인원이라고? 그걸 왜 이제 와서 말하는 것이오?","JPN":"必要な人員だと？　それをどうして今になって話すのだ？","ENG":"Required personnel? Why are you telling us that now?","TWN":"需要的人員？這種事你為什麼現在才說？"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"어머나, 인간 주제에 그렇게 사나운 말투를 쓰면 어떡해. 부드럽게 짖으렴.","JPN":"あら、人間の分際でその荒い言葉遣いは何なのかしら。優しく吠えなさい。","ENG":"Oh dear. Bark softly, human. Don't use that tone with me.","TWN":"哎呦，區區人類，說話口氣怎麼這麼凶，溫柔點。"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};